-- M168 skill analytics (#2010). Records each skill invocation so usage
-- (frequency / recency, per session) is queryable from the coordination DB
-- instead of the append-only .claude/logs/skill-usage.log. Adoption rate
-- (taken / suggested) is intentionally NOT here — there is no suggest-side
-- on main yet; that lands with the recommender (umbrella #2006, follow-up).

PRAGMA user_version = 2;

CREATE TABLE IF NOT EXISTS skill_invocation (
    session_id  TEXT NOT NULL REFERENCES sessions(sid) ON DELETE CASCADE,
    skill       TEXT NOT NULL,
    invoked_at  INTEGER NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_skill_invocation ON skill_invocation(session_id, skill);
